#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int count_numbers(const char *s) {
    int cnt = 0, in = 0;
    while (*s) {
        if (*s != ' ' && *s != '\n' && *s != '\r' && *s != '\t') {
            if (!in) { in = 1; cnt++; }
        } else {
            in = 0;
        }
        s++;
    }
    return cnt;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[5000];
        // read array line
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0';
        int N = count_numbers(line);
        int *arr = (int*)malloc((N + 1) * sizeof(int));
        char *token = strtok(line, " ");
        for (int i = 0; i < N; ++i) {
            arr[i] = atoi(token);
            token = strtok(NULL, " ");
        }
        int index, element;
        scanf("%d %d", &index, &element);
        getchar(); // consume newline after the second line
        for (int i = N; i > index; --i) {
            arr[i] = arr[i-1];
        }
        arr[index] = element;
        for (int i = 0; i <= N; ++i) {
            if (i) printf(" ");
            printf("%d", arr[i]);
        }
        if (tc != T-1) printf("\n");
        free(arr);
    }
    return 0;
}

