        stringstream ss(arrLine);
        vector<int> a;
        int x;
        while (ss >> x) a.push_back(x);
        int index, element;
        cin >> index >> element;
        getline(cin, dummy); // consume end of line after index/element line
        a.insert(a.begin() + index, element);
        for (size_t i = 0; i < a.size(); ++i) {
            if (i) cout << ' ';
            cout << a[i];
        }
        if (tc != T-1) cout << '\n';
    }
