code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String arrLine = br.readLine();
            while (arrLine != null && arrLine.trim().isEmpty()) arrLine = br.readLine();
            StringTokenizer st = new StringTokenizer(arrLine);
            List<Integer> list = new ArrayList<>();
            while (st.hasMoreTokens()) {
                list.add(Integer.parseInt(st.nextToken()));
            }
            String[] idxElem = br.readLine().trim().split(" ");
            int index = Integer.parseInt(idxElem[0]);
            int element = Integer.parseInt(idxElem[1]);
            list.add(index, element);
            for (int i = 0; i < list.size(); ++i) {
                if (i > 0) out.append(' ');
                out.append(list.get(i));
            }
            if (tc != T-1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

